import{_ as t,c as i,a3 as a,o as r}from"./chunks/framework.VX8o9GSp.js";const u=JSON.parse('{"title":"git-crypt 官方文档","description":"","frontmatter":{"prev":false,"next":false,"date":"2024-07-08T00:00:00.000Z","tags":["git-crypt","git"],"categories":["计算机"]},"headers":[],"relativePath":"2024/07/git-crypt_official_doc.md","filePath":"2024/07/git-crypt_official_doc.md","lastUpdated":1729262595000}'),s={name:"2024/07/git-crypt_official_doc.md"};function n(o,e,p,c,l,d){return r(),i("div",null,e[0]||(e[0]=[a(`<h1 id="git-crypt-官方文档" tabindex="-1">git-crypt 官方文档 <a class="header-anchor" href="#git-crypt-官方文档" aria-label="Permalink to &quot;git-crypt 官方文档&quot;">​</a></h1><blockquote><p>原文档: <a href="https://github.com/AGWA/git-crypt/blob/master/README.md" target="_blank" rel="noreferrer">https://github.com/AGWA/git-crypt/blob/master/README.md</a></p></blockquote><h2 id="git-crypt-transparent-file-encryption-in-git" tabindex="-1">git -crypt - transparent file encryption in git <a class="header-anchor" href="#git-crypt-transparent-file-encryption-in-git" aria-label="Permalink to &quot;git -crypt - transparent file encryption in git&quot;">​</a></h2><p>git-crypt enables transparent encryption and decryption of files in a git repository. Files which you choose to protect are encrypted when committed, and decrypted when checked out. git-crypt lets you freely share a repository containing a mix of public and private content. git-crypt gracefully degrades, so developers without the secret key can still clone and commit to a repository with encrypted files. This lets you store your secret material (such as keys or passwords) in the same repository as your code, without requiring you to lock down your entire repository.</p><p>git-crypt was written by <a href="https://www.agwa.name" target="_blank" rel="noreferrer">Andrew Ayer</a> (<a href="mailto:agwa@andrewayer.name" target="_blank" rel="noreferrer">agwa@andrewayer.name</a>). For more information, see <a href="https://www.agwa.name/projects/git-crypt" target="_blank" rel="noreferrer">https://www.agwa.name/projects/git-crypt</a>.</p><h2 id="building-git-crypt" tabindex="-1">Building git-crypt <a class="header-anchor" href="#building-git-crypt" aria-label="Permalink to &quot;Building git-crypt&quot;">​</a></h2><p>See the <a href="https://github.com/AGWA/git-crypt/blob/master/INSTALL.md" target="_blank" rel="noreferrer">INSTALL.md</a> file.</p><h2 id="using-git-crypt" tabindex="-1">Using git-crypt <a class="header-anchor" href="#using-git-crypt" aria-label="Permalink to &quot;Using git-crypt&quot;">​</a></h2><p>Configure a repository to use git-crypt:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd repo</span></span>
<span class="line"><span>git-crypt init</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Specify files to encrypt by creating a .gitattributes file:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>secretfile filter=git-crypt diff=git-crypt</span></span>
<span class="line"><span>*.key filter=git-crypt diff=git-crypt</span></span>
<span class="line"><span>secretdir/** filter=git-crypt diff=git-crypt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Like a .gitignore file, it can match wildcards and should be checked into the repository. See below for more information about .gitattributes. Make sure you don&#39;t accidentally encrypt the .gitattributes file itself (or other git files like .gitignore or .gitmodules). Make sure your .gitattributes rules are in place <em>before</em> you add sensitive files, or those files won&#39;t be encrypted!</p><p>Share the repository with others (or with yourself) using GPG:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git-crypt add-gpg-user USER_ID</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>USER_ID</code> can be a key ID, a full fingerprint, an email address, or anything else that uniquely identifies a public key to GPG (see &quot;HOW TO SPECIFY A USER ID&quot; in the gpg man page). Note: <code>git-crypt add-gpg-user</code> will add and commit a GPG-encrypted key file in the .git-crypt directory of the root of your repository.</p><p>Alternatively, you can export a symmetric secret key, which you must securely convey to collaborators (GPG is not required, and no files are added to your repository):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git-crypt export-key /path/to/key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>After cloning a repository with encrypted files, unlock with GPG:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git-crypt unlock</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Or with a symmetric key:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git-crypt unlock /path/to/key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>That&#39;s all you need to do - after git-crypt is set up (either with <code>git-crypt init</code> or <code>git-crypt unlock</code>), you can use git normally - encryption and decryption happen transparently.</p><h2 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to &quot;Current Status&quot;">​</a></h2><p>The latest version of git-crypt is <a href="https://github.com/AGWA/git-crypt/blob/master/NEWS.md" target="_blank" rel="noreferrer">0.7.0</a>, released on 2022-04-21. git-crypt aims to be bug-free and reliable, meaning it shouldn&#39;t crash, malfunction, or expose your confidential data. However, it has not yet reached maturity, meaning it is not as documented, featureful, or easy-to-use as it should be. Additionally, there may be backwards-incompatible changes introduced before version 1.0.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p>git-crypt is more secure than other transparent git encryption systems. git-crypt encrypts files using AES-256 in CTR mode with a synthetic IV derived from the SHA-1 HMAC of the file. This mode of operation is provably semantically secure under deterministic chosen-plaintext attack. That means that although the encryption is deterministic (which is required so git can distinguish when a file has and hasn&#39;t changed), it leaks no information beyond whether two files are identical or not. Other proposals for transparent git encryption use ECB or CBC with a fixed IV. These systems are not semantically secure and leak information.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><p>git-crypt relies on git filters, which were not designed with encryption in mind. As such, git-crypt is not the best tool for encrypting most or all of the files in a repository. Where git-crypt really shines is where most of your repository is public, but you have a few files (perhaps private keys named *.key, or a file with API credentials) which you need to encrypt. For encrypting an entire repository, consider using a system like <a href="https://spwhitton.name/tech/code/git-remote-gcrypt/" target="_blank" rel="noreferrer">git-remote-gcrypt</a> instead. (Note: no endorsement is made of git-remote-gcrypt&#39;s security.)</p><p>git-crypt does not encrypt file names, commit messages, symlink targets, gitlinks, or other metadata.</p><p>git-crypt does not hide when a file does or doesn&#39;t change, the length of a file, or the fact that two files are identical (see &quot;Security&quot; section above).</p><p>git-crypt does not support revoking access to an encrypted repository which was previously granted. This applies to both multi-user GPG mode (there&#39;s no del-gpg-user command to complement add-gpg-user) and also symmetric key mode (there&#39;s no support for rotating the key). This is because it is an inherently complex problem in the context of historical data. For example, even if a key was rotated at one point in history, a user having the previous key can still access previous repository history. This problem is discussed in more detail in <a href="https://github.com/AGWA/git-crypt/issues/47" target="_blank" rel="noreferrer">https://github.com/AGWA/git-crypt/issues/47</a>.</p><p>Files encrypted with git-crypt are not compressible. Even the smallest change to an encrypted file requires git to store the entire changed file, instead of just a delta.</p><p>Although git-crypt protects individual file contents with a SHA-1 HMAC, git-crypt cannot be used securely unless the entire repository is protected against tampering (an attacker who can mutate your repository can alter your .gitattributes file to disable encryption). If necessary, use git features such as signed tags instead of relying solely on git-crypt for integrity.</p><p>Files encrypted with git-crypt cannot be patched with git-apply, unless the patch itself is encrypted. To generate an encrypted patch, use <code>git diff --no-textconv --binary</code>. Alternatively, you can apply a plaintext patch outside of git using the patch command.</p><p>git-crypt does not work reliably with some third-party git GUIs, such as <a href="https://jira.atlassian.com/browse/SRCTREE-2511" target="_blank" rel="noreferrer">Atlassian SourceTree</a> and GitHub for Mac. Files might be left in an unencrypted state.</p><h2 id="gitattributes-file" tabindex="-1">Gitattributes File <a class="header-anchor" href="#gitattributes-file" aria-label="Permalink to &quot;Gitattributes File&quot;">​</a></h2><p>The .gitattributes file is documented in the gitattributes(5) man page. The file pattern format is the same as the one used by .gitignore, as documented in the gitignore(5) man page, with the exception that specifying merely a directory (e.g. <code>/dir/</code>) is <em>not</em> sufficient to encrypt all files beneath it.</p><p>Also note that the pattern <code>dir/*</code> does not match files under sub-directories of dir/. To encrypt an entire sub-tree dir/, use <code>dir/**</code>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dir/** filter=git-crypt diff=git-crypt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The .gitattributes file must not be encrypted, so make sure wildcards don&#39;t match it accidentally. If necessary, you can exclude .gitattributes from encryption like this:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.gitattributes !filter !diff</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,42)]))}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
